import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_BASE = 'http://localhost:8000';

const NotificationSettings = ({ onClose }) => {
    const [settings, setSettings] = useState({
        cpu_threshold: 85,
        mem_threshold: 90,
        email_enabled: false,
        email_address: '',
        slack_enabled: false,
        slack_webhook: '',
        pagerduty_enabled: false,
        pagerduty_url: '',
    });
    const [saved, setSaved] = useState(false);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    // Load current settings from backend on open
    useEffect(() => {
        const fetchSettings = async () => {
            try {
                const { data } = await axios.get(`${API_BASE}/api/settings`);
                setSettings(prev => ({ ...prev, ...data }));
            } catch (err) {
                // Backend may not have saved settings yet — defaults are fine
            } finally {
                setLoading(false);
            }
        };
        fetchSettings();
    }, []);

    const handleSave = async () => {
        try {
            await axios.post(`${API_BASE}/api/settings`, settings);
            setSaved(true);
            setTimeout(() => setSaved(false), 2500);
            setError(null);
        } catch (err) {
            setError('Failed to save settings. Make sure the backend is running.');
        }
    };

    const toggle = (field) => {
        setSettings(prev => ({ ...prev, [field]: !prev[field] }));
    };

    const update = (field, value) => {
        setSettings(prev => ({ ...prev, [field]: value }));
    };

    // Close on backdrop click
    const handleBackdrop = (e) => {
        if (e.target === e.currentTarget) onClose();
    };

    return (
        <div
            onClick={handleBackdrop}
            style={{
                position: 'fixed', inset: 0,
                backgroundColor: 'rgba(0,0,0,0.7)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                zIndex: 1000
            }}
        >
            <div style={{
                backgroundColor: '#1f2937',
                border: '1px solid #374151',
                borderRadius: '0.75rem',
                width: '100%',
                maxWidth: '520px',
                padding: '2rem',
                position: 'relative',
                boxShadow: '0 25px 50px rgba(0,0,0,0.5)'
            }}>

                {/* Header */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.75rem' }}>
                    <div>
                        <h2 style={{ color: '#f3f4f6', margin: 0, fontSize: '1.25rem' }}>
                            ⚙️ Notification Settings
                        </h2>
                        <p style={{ color: '#9ca3af', fontSize: '0.8rem', margin: '0.25rem 0 0 0' }}>
                            Configure alert thresholds and notification channels
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        style={{
                            backgroundColor: 'transparent', border: 'none',
                            color: '#9ca3af', fontSize: '1.5rem', cursor: 'pointer',
                            lineHeight: 1
                        }}
                    >
                        ×
                    </button>
                </div>

                {loading ? (
                    <div style={{ color: '#9ca3af', textAlign: 'center', padding: '2rem' }}>
                        Loading settings...
                    </div>
                ) : (
                    <>
                        {/* ---- THRESHOLDS ---- */}
                        <section style={{ marginBottom: '1.75rem' }}>
                            <h3 style={{ color: '#4ade80', fontSize: '0.8rem', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                                Alert Thresholds
                            </h3>

                            {/* CPU threshold */}
                            <div style={{ marginBottom: '1rem' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.4rem' }}>
                                    <label style={{ color: '#d1d5db', fontSize: '0.9rem' }}>CPU Usage Threshold</label>
                                    <span style={{ color: '#4ade80', fontWeight: 'bold', fontFamily: 'monospace' }}>
                                        {settings.cpu_threshold}%
                                    </span>
                                </div>
                                <input
                                    type="range" min="50" max="99"
                                    value={settings.cpu_threshold}
                                    onChange={e => update('cpu_threshold', parseInt(e.target.value))}
                                    style={{ width: '100%', accentColor: '#4ade80' }}
                                />
                                <div style={{ display: 'flex', justifyContent: 'space-between', color: '#6b7280', fontSize: '0.7rem' }}>
                                    <span>50%</span><span>Alert fires above this value</span><span>99%</span>
                                </div>
                            </div>

                            {/* Memory threshold */}
                            <div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.4rem' }}>
                                    <label style={{ color: '#d1d5db', fontSize: '0.9rem' }}>Memory Usage Threshold</label>
                                    <span style={{ color: '#4ade80', fontWeight: 'bold', fontFamily: 'monospace' }}>
                                        {settings.mem_threshold}%
                                    </span>
                                </div>
                                <input
                                    type="range" min="50" max="99"
                                    value={settings.mem_threshold}
                                    onChange={e => update('mem_threshold', parseInt(e.target.value))}
                                    style={{ width: '100%', accentColor: '#4ade80' }}
                                />
                                <div style={{ display: 'flex', justifyContent: 'space-between', color: '#6b7280', fontSize: '0.7rem' }}>
                                    <span>50%</span><span>Alert fires above this value</span><span>99%</span>
                                </div>
                            </div>
                        </section>

                        <div style={{ borderTop: '1px solid #374151', marginBottom: '1.75rem' }} />

                        {/* ---- CHANNELS ---- */}
                        <section style={{ marginBottom: '1.75rem' }}>
                            <h3 style={{ color: '#4ade80', fontSize: '0.8rem', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                                Notification Channels
                            </h3>

                            {/* Email */}
                            <ChannelRow
                                label="Email"
                                icon="📧"
                                enabled={settings.email_enabled}
                                onToggle={() => toggle('email_enabled')}
                                placeholder="alerts@yourcompany.com"
                                value={settings.email_address}
                                onChange={v => update('email_address', v)}
                                note="Requires SMTP config in backend"
                            />

                            {/* Slack */}
                            <ChannelRow
                                label="Slack Webhook"
                                icon="💬"
                                enabled={settings.slack_enabled}
                                onToggle={() => toggle('slack_enabled')}
                                placeholder="https://hooks.slack.com/services/..."
                                value={settings.slack_webhook}
                                onChange={v => update('slack_webhook', v)}
                                note="Paste your Slack incoming webhook URL"
                            />

                            {/* PagerDuty */}
                            <ChannelRow
                                label="SMS / PagerDuty"
                                icon="📟"
                                enabled={settings.pagerduty_enabled}
                                onToggle={() => toggle('pagerduty_enabled')}
                                placeholder="https://events.pagerduty.com/..."
                                value={settings.pagerduty_url}
                                onChange={v => update('pagerduty_url', v)}
                                note="PagerDuty Events API v2 endpoint"
                            />
                        </section>

                        {/* Error / success */}
                        {error && (
                            <div style={{
                                backgroundColor: 'rgba(239,68,68,0.1)',
                                border: '1px solid #ef4444',
                                borderRadius: '0.375rem',
                                padding: '0.5rem 0.75rem',
                                color: '#f87171',
                                fontSize: '0.8rem',
                                marginBottom: '1rem'
                            }}>
                                {error}
                            </div>
                        )}

                        {saved && (
                            <div style={{
                                backgroundColor: 'rgba(74,222,128,0.1)',
                                border: '1px solid #4ade80',
                                borderRadius: '0.375rem',
                                padding: '0.5rem 0.75rem',
                                color: '#4ade80',
                                fontSize: '0.8rem',
                                marginBottom: '1rem'
                            }}>
                                ✓ Settings saved and applied to alert engine
                            </div>
                        )}

                        {/* Buttons */}
                        <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end' }}>
                            <button
                                onClick={onClose}
                                style={{
                                    backgroundColor: 'transparent',
                                    border: '1px solid #374151',
                                    color: '#9ca3af',
                                    borderRadius: '0.375rem',
                                    padding: '0.5rem 1.25rem',
                                    cursor: 'pointer',
                                    fontSize: '0.9rem'
                                }}
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleSave}
                                style={{
                                    backgroundColor: '#4ade80',
                                    border: 'none',
                                    color: '#111827',
                                    borderRadius: '0.375rem',
                                    padding: '0.5rem 1.25rem',
                                    cursor: 'pointer',
                                    fontWeight: 'bold',
                                    fontSize: '0.9rem'
                                }}
                            >
                                Save Settings
                            </button>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
};

// Reusable channel row component
const ChannelRow = ({ label, icon, enabled, onToggle, placeholder, value, onChange, note }) => (
    <div style={{
        backgroundColor: '#111827',
        border: '1px solid #374151',
        borderRadius: '0.5rem',
        padding: '1rem',
        marginBottom: '0.75rem'
    }}>
        {/* Toggle row */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: enabled ? '0.75rem' : 0 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <span>{icon}</span>
                <span style={{ color: '#f3f4f6', fontSize: '0.9rem', fontWeight: '500' }}>{label}</span>
            </div>

            {/* Toggle switch */}
            <div
                onClick={onToggle}
                style={{
                    width: '44px', height: '24px',
                    backgroundColor: enabled ? '#4ade80' : '#374151',
                    borderRadius: '9999px',
                    cursor: 'pointer',
                    position: 'relative',
                    transition: 'background-color 0.2s'
                }}
            >
                <div style={{
                    position: 'absolute',
                    top: '3px',
                    left: enabled ? '23px' : '3px',
                    width: '18px', height: '18px',
                    backgroundColor: 'white',
                    borderRadius: '50%',
                    transition: 'left 0.2s'
                }} />
            </div>
        </div>

        {/* Input — only shown when enabled */}
        {enabled && (
            <>
                <input
                    type="text"
                    placeholder={placeholder}
                    value={value}
                    onChange={e => onChange(e.target.value)}
                    style={{
                        width: '100%',
                        backgroundColor: '#1f2937',
                        border: '1px solid #4b5563',
                        borderRadius: '0.375rem',
                        padding: '0.5rem 0.75rem',
                        color: '#f3f4f6',
                        fontSize: '0.85rem',
                        outline: 'none',
                        boxSizing: 'border-box'
                    }}
                />
                <div style={{ color: '#6b7280', fontSize: '0.7rem', marginTop: '0.35rem' }}>
                    {note}
                </div>
            </>
        )}
    </div>
);

export default NotificationSettings;
